export default function Dashboard() {
  return (
    <div className="p-6 space-y-12">
      <h2 className="text-2xl font-bold mb-2">📊 Statystyki systemowe</h2>
      <SystemStats />

      <h2 className="text-2xl font-bold mt-8 mb-2">🥧 Wykres statystyk alertów</h2>
      <PieChartStats />

      <h2 className="text-2xl font-bold mt-8 mb-2">🧾 Tabela alertów</h2>
      <AlertTable />
    </div>
  );
}
